/* SQL ID : ExamStareDAO.selectExamScoreStatus 설 명 : 시험 현황 조회 */
SELECT NVL(SUM(CASE WHEN A.STARE_STATUS_CD = 'N' THEN 1 ELSE 0 END), 0) AS NO_STARE_CNT , NVL(SUM(CASE WHEN A.STARE_STATUS_CD = 'T' THEN 1 ELSE 0 END), 0) AS TEMP_SAVE_CNT , NVL(SUM(CASE WHEN A.STARE_STATUS_CD = 'C' THEN 1 ELSE 0 END), 0) AS COMPLETE_CNT , NVL(ROUND(AVG(A.ACQS_TOT_SCR)), 0) AS AVG_SCORE , NVL(MAX(A.ACQS_TOT_SCR), 0) AS MAX_SCORE , NVL(MIN(A.ACQS_TOT_SCR), 0) AS MIN_SCORE , NVL(ROUND(SUM(CASE WHEN A.LINE_NO <= A.CNT THEN A.ACQS_TOT_SCR ELSE 0 END) / A.CNT), 0) AS TOP_AVG_SCORE
FROM (
SELECT ROW_NUMBER() OVER(ORDER BY CASE EXAM_TYCD WHEN 'EXAM' THEN D.ACQS_TOT_SCR WHEN 'QUIZ' THEN G.ACQS_TOT_SCR WHEN 'ASMNT' THEN E.SCR WHEN 'FORUM' THEN F.SCR END DESC) AS LINE_NO , CASE EXAM_TYCD WHEN 'EXAM' THEN CASE WHEN D.STARE_CNT > 0 THEN 'C' ELSE 'N' END WHEN 'QUIZ' THEN CASE WHEN G.SDTTM IS NULL THEN 'N' WHEN G.EDTTM IS NULL THEN 'T' WHEN G.EDTTM IS NOT NULL THEN 'C' END WHEN 'ASMNT' THEN CASE WHEN E.SBMSN_STSCD = 'SUBMIT' THEN 'C' ELSE 'N' END WHEN 'FORUM' THEN CASE WHEN (SELECT COUNT(1) FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = F.DSCS_ID AND DELYN = 'N' AND STD_ID = C.STD_ID) + (SELECT COUNT(1) FROM TB_LMS_DSCS_CMNT WHERE DSCS_ID = f.DSCS_ID AND DELYN = 'N' AND STD_ID = C.STD_ID) = 0 THEN 'N' ELSE 'C' END END AS STARE_STATUS_CD , NVL(CASE EXAM_TYCD WHEN 'EXAM' THEN D.ACQS_TOT_SCR WHEN 'QUIZ' THEN G.ACQS_TOT_SCR WHEN 'ASMNT' THEN E.SCR WHEN 'FORUM' THEN F.SCR END, 0) AS ACQS_TOT_SCR , COUNT(1) OVER() / 10 AS CNT
FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.SBJCT_ID = #{crsCreCd} AND A.DELYN = 'N' AND B.DELYN = 'N' JOIN TB_LMS_ATNDLC_SBJCT C ON B.SBJCT_ID = C.SBJCT_ID AND C.ATNDLC_STSCD NOT IN('D', 'T') LEFT JOIN TB_LMS_EXAM_STARE D ON A.EXAM_ID = D.EXAM_ID AND C.STD_ID = D.STD_ID LEFT JOIN TB_LMS_ASMT_SBMSN E ON A.EXAM_SBST_REF_ID = E.ASMT_ID AND C.STD_ID = E.STD_ID LEFT JOIN TB_LMS_DSCS_PTCP F ON A.EXAM_SBST_REF_ID = F.DSCS_ID AND C.STD_ID = F.STD_ID LEFT JOIN TB_LMS_EXAM_STARE G ON A.EXAM_SBST_REF_ID = G.EXAM_ID AND C.STD_ID = G.STD_ID WHERE A.EXAM_CTGRCD = 'EXAM' AND C.AUDITYN = 'N' AND A.EXAM_ID = ( SELECT EXAM_ID FROM( SELECT ROW_NUMBER() OVER(ORDER BY AA.EXAM_SDTTM DESC) AS RN , AA.EXAM_ID FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID AND AA.EXAM_CTGRCD = 'EXAM' AND AA.TKEXAM_TYCD = 'M' AND AA.DELYN = 'N' AND BB.DELYN = 'N' WHERE BB.SBJCT_ID = '202510CME00001' ) WHERE RN = 1 )
SELECT ROW_NUMBER() OVER(ORDER BY A.ACQS_TOT_SCR DESC) AS LINE_NO , ( SELECT CASE WHEN AA.EXAM_CTGRCD = 'EXAM' THEN CASE WHEN A.STARE_CNT > 0 THEN 'C' ELSE 'N' END ELSE CASE WHEN A.SDTTM IS NULL THEN 'N' WHEN A.EDTTM IS NULL THEN 'T' WHEN A.EDTTM IS NOT NULL THEN 'C' END END FROM TB_LMS_EXAM_BSC AA WHERE AA.EXAM_ID = A.EXAM_ID ) AS STARE_STATUS_CD , NVL(A.ACQS_TOT_SCR, 0) AS ACQS_TOT_SCR , COUNT(1) OVER() / 10 AS CNT
FROM TB_LMS_ATNDLC_SBJCT S JOIN TB_LMS_USER_ACNT B ON S.USER_ID = B.USER_ID AND B.ACNT_STSCD = 'U' LEFT JOIN TB_LMS_EXAM_STARE A ON S.STD_ID = A.STD_ID AND A.DELYN = 'N' AND A.EXAM_ID = #{examCd}
JOIN TB_LMS_EXAM_STARE C ON C.EXAM_ID = (SELECT EXAM_ID FROM TB_LMS_EXAM_BSC WHERE EXAM_SBST_REF_ID = #{examCd} AND DELYN = 'N') AND S.STD_ID = C.STD_ID AND C.REEXAMYN = 'Y'
WHERE S.SBJCT_ID = #{crsCreCd} AND S.ATNDLC_STSCD = 'S' AND S.AUDITYN = 'N'
) A GROUP BY A.CNT

mapper.insert:
    	/*
       		SQL ID : ExamStareDAO.insertExamStare
       		설  명 : 시험응시 등록
         */

    	INSERT INTO TB_LMS_EXAM_STARE (
    		  STD_ID
			, EXAM_ID
			, STARE_SN
			, STARE_CNT
			, STARE_TM
			, SDTTM
			, EDTTM
			, ADDNDM_CTS
			, EVL_DTTM
			, EVLYN
			, REEXAMYN
			, DELYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
    	) SELECT
	    	  #{stdNo}
			, #{examCd}
			, #{stareSn}
			, #{stareCnt}
			, #{stareTm}
			, #{startDttm}
			, #{endDttm}
			, #{atchCts}
			, #{evalDttm}
			, #{evalYn}
			, #{reExamYn}
			, 'N'
			, #{rgtrId}
			, FN_DTTM()
			, #{mdfrId}
			, FN_DTTM()
		FROM DUAL
		WHERE NOT EXISTS (
			SELECT 1
			FROM TB_LMS_EXAM_STARE
			WHERE STD_ID = #{stdNo}
				AND EXAM_ID = #{examCd}
		)

    	/*
       		SQL ID : ExamStareDAO.insertExamStareBatch
       		설  명 : 시험응시 일괄 등록
         */
        INSERT ALL 

    	INTO TB_LMS_EXAM_STARE (
    		  STD_ID
			, EXAM_ID
			, STARE_SN
			, STARE_CNT
			, STARE_TM
			, SDTTM
			, EDTTM
			, ADDNDM_CTS
			, EVL_DTTM
			, EVLYN
			, REEXAMYN
			, DELYN
			, RGTR_ID
			, FRST_INQ_DTTM
			, MDFR_ID
			, MOD_DTTM
    	) VALUES (
    		  #{item.stdNo}
			, #{item.examCd}
			, #{item.stareSn}
			, #{item.stareCnt}
			, #{item.stareTm}
			, #{item.startDttm}
			, #{item.endDttm}
			, #{item.atchCts}
			, #{item.evalDttm}
			, #{item.evalYn}
			, #{item.reExamYn}
			, 'N'
			, #{item.rgtrId}
			, FN_DTTM()
			, #{item.mdfrId}
			, FN_DTTM()
    	)

		SELECT * FROM SYS.DUAL

mapper.update:
    	/*
       		SQL ID : ExamStareDAO.updateExamStare
       		설  명 : 시험응시 수정
         */
    	UPDATE TB_LMS_EXAM_STARE SET
    		  MDFR_ID = #{mdfrId}
    		, MOD_DTTM = FN_DTTM()

    		, ACQS_TOT_SCR = #{totGetScore}


			, STARE_CNT = #{stareCnt}


			, STARE_TM = #{stareTm}


			, SDTTM = #{startDttm}


			, EDTTM = #{endDttm}


			, ADDNDM_CTS = #{atchCts}


			, EVLYN = #{evalYn}
			, EVL_DTTM = FN_DTTM()


			, REEXAMYN = #{reExamYn}


    		, SCR_MEMO = #{profMemo}


			, DELYN = #{delYn}

    	 WHERE STD_ID = #{stdNo}
    	   AND EXAM_ID = #{examCd}

/* SQL ID : ExamStareDAO.updateReExamStare 설 명 : 재시험 설정 */ UPDATE TB_LMS_EXAM_STARE SET MDFR_ID = #{mdfrId} , MOD_DTTM = FN_DTTM() , ACQS_TOT_SCR = NULL , STARE_CNT = 0 , STARE_TM = 0 , SDTTM = NULL , EDTTM = NULL , EVL_DTTM = NULL , EVLYN = 'N'
, REEXAMYN = #{reExamYn}
WHERE EXAM_ID = #{examCd} AND STD_ID IN
#{item}

        /*
       		SQL ID : ExamStareDAO.updateExamStareScore
       	 	설  명 : 학습자 토탈 시험 점수 수정
        */
        UPDATE TB_LMS_EXAM_STARE
           SET MDFR_ID = #{mdfrId}
             , MOD_DTTM = FN_DTTM()
             , EVLYN = 'Y'
             , EVL_DTTM = FN_DTTM()
             , ACQS_TOT_SCR =



					(
					SELECT
						ACQS_TOT_SCR
					FROM(
						SELECT
							CASE
								WHEN NVL(ACQS_TOT_SCR, 0.0) + #{totGetScore} < 0.0	  THEN 0.0
								WHEN NVL(ACQS_TOT_SCR, 0.0) + #{totGetScore} > 100.0 THEN 100.0
		  						ELSE NVL(ACQS_TOT_SCR, 0.0) + #{totGetScore}
							END AS ACQS_TOT_SCR
	           			FROM TB_LMS_EXAM_STARE
	               		WHERE EXAM_ID = #{examCd}
	               		  AND STD_ID = #{stdNo}
					) TMP)



					#{totGetScore}


         WHERE EXAM_ID = #{examCd}
           AND STD_ID = #{stdNo}

mapper.select:
/* SQL ID : ExamStareDAO.listExamTargetStd 설 명 : 시험 설정 대상 학습자 번호 조회 */ SELECT A.STD_ID AS stdNo , A.EXAM_ID AS examCd , A.ACQS_TOT_SCR AS totGetScore , IFNULL(( SELECT SUM(AA.ACQS_SCR) FROM TB_LMS_EXAM_STARE_PAPER AA WHERE AA.EXAM_ID = A.EXAM_ID AND AA.STD_ID = A.STD_ID ), 0) AS stareScore , A.EVLYN AS evalYn , A.STD_ID AS stdNo , C.STARE_STATUS_CD AS stareStatusCd , A.SDTTM AS startDttm , A.EDTTM AS endDttm , A.EVL_DTTM AS evalDttm , A.REEXAMYN AS reExamYn , A.STARE_CNT AS stareCnt , A.STARE_TM AS stareTm FROM TB_LMS_EXAM_STARE A JOIN ( SELECT CASE WHEN BB.EXAM_CTGRCD = 'EXAM THEN CASE WHEN B.STARE_CNT > 0 THEN 'C' ELSE 'N' END ELSE CASE WHEN B.SDTTM IS NULL THEN 'N' WHEN B.EDTTM IS NULL THEN 'T' WHEN B.EDTTM IS NOT NULL THEN 'C' END END AS STARE_STATUS_CD ,B.EXAM_ID ,B.STD_ID FROM TB_LMS_EXAM_STARE B JOIN TB_LMS_EXAM_BSC BB ON B.EXAM_ID = BB.EXAM_ID AND BB.DELYN = 'N' ) C ON A.EXAM_ID = C.EXAM_ID AND A.STD_ID = C.STD_ID WHERE A.EXAM_ID = #{examCd}
AND A.STD_ID IN
#{item}
AND C.STARE_STATUS_CD = #{stareStatusCd}

mapper.update:
 /*
		SQL ID : ExamStareDAO.updateExamStareTempSave
	 	설  명 : 시험 응시 임시저장
 */
 UPDATE TB_LMS_EXAM_STARE
    SET MDFR_ID = #{mdfrId}
      , MOD_DTTM = FN_DTTM()

      , STARE_TM = STARE_TM + #{stareTm}


      , EDTTM = FN_DTTM()
      , STARE_CNT = STARE_CNT + 1


      , ACQS_TOT_SCR = #{totGetScore}


 	, EVLYN = #{evalYn}

  WHERE EXAM_ID = #{examCd}
    AND STD_ID = #{stdNo}

mapper.select:
/* SQL ID : ExamStareDAO.listStuExamScoreStatus 설 명 : 시험에 응시한 학습자의 점수대역별 통계정보 조회 */
WITH SCORE_T AS ( SELECT -1 AS SP, 10 AS EP, '0~10' AS LABEL, 1 AS ODR FROM dual UNION ALL SELECT 10, 20, '11~20', 2 FROM dual UNION ALL SELECT 20, 30, '21~30', 3 FROM dual UNION ALL SELECT 30, 40, '31~40', 4 FROM dual UNION ALL SELECT 40, 50, '41~50', 5 FROM dual UNION ALL SELECT 50, 60, '51~60', 6 FROM dual UNION ALL SELECT 60, 70, '61~70', 7 FROM dual UNION ALL SELECT 70, 80, '71~80', 8 FROM dual UNION ALL SELECT 80, 90, '81~90', 9 FROM dual UNION ALL SELECT 90, 100, '91~100', 10 FROM dual ), LATEST_EXAM AS ( SELECT EXAM_ID, EXAM_SBST_REF_ID, EXAM_TYCD FROM ( SELECT ROW_NUMBER() OVER (ORDER BY AA.EXAM_SDTTM DESC) AS RN , AA.EXAM_ID , AA.EXAM_SBST_REF_ID , AA.EXAM_TYCD FROM TB_LMS_EXAM_BSC AA JOIN TB_LMS_EXAM_CRE_CRS_RLTN BB ON AA.EXAM_ID = BB.EXAM_ID WHERE 1 = 1 AND BB.SBJCT_ID = #{crsCreCd} AND AA.EXAM_CTGRCD = 'EXAM' AND AA.TKEXAM_TYCD = #{examStareTypeCd} AND AA.DELYN = 'N' AND BB.DELYN = 'N'
AND AA.EXAM_ID = #{examCd}
) WHERE RN = 1 ), STD_T AS ( SELECT S.STD_ID , S.SBJCT_ID FROM TB_LMS_ATNDLC_SBJCT S WHERE S.ATNDLC_STSCD = 'S' AND S.AUDITYN = 'N' AND S.SBJCT_ID = #{crsCreCd} ), EXAM_SCORE_RAW AS ( SELECT B.STD_ID , B.SBJCT_ID , A.EXAM_ID , A.EXAM_SBST_REF_ID , A.EXAM_TYCD , E.REEXAMYN , CASE WHEN E.REEXAMYN = 'Y' THEN CASE REGEXP_SUBSTR(A.EXAM_SBST_REF_ID, '[^_]+', 1, 1) WHEN 'EXAM' THEN ( SELECT ACQS_TOT_SCR FROM TB_LMS_EXAM_STARE WHERE STD_ID = B.STD_ID AND EXAM_ID = A.EXAM_SBST_REF_ID AND DELYN = 'N' ) WHEN 'ASMNT' THEN ( SELECT SCR FROM TB_LMS_ASMT_SBMSN WHERE STD_ID = B.STD_ID AND ASMT_ID = A.EXAM_SBST_REF_ID AND DELYN = 'N' ) WHEN 'FORUM' THEN ( SELECT SCR FROM TB_LMS_DSCS_PTCP WHERE STD_ID = B.STD_ID AND DSCS_ID = A.EXAM_SBST_REF_ID AND DELYN = 'N' ) END ELSE ( SELECT ACQS_TOT_SCR FROM TB_LMS_EXAM_STARE WHERE STD_ID = B.STD_ID AND EXAM_ID = A.EXAM_ID AND DELYN = 'N' ) END AS SCR FROM STD_T B CROSS JOIN LATEST_EXAM A LEFT JOIN TB_LMS_EXAM_STARE E ON E.EXAM_ID = A.EXAM_ID AND E.STD_ID = B.STD_ID AND E.DELYN = 'N' )
SELECT T.LABEL , COUNT(*) AS CNT FROM SCORE_T T JOIN EXAM_SCORE_RAW S ON T.SP < NVL(S.SCR, 0) AND T.EP >= NVL(S.SCR, 0) GROUP BY T.LABEL, T.ODR
SELECT T.LABEL AS LABEL , COUNT(B.STD_ID) AS CNT FROM SCORE_T T CROSS JOIN TB_LMS_EXAM_BSC A LEFT JOIN TB_LMS_EXAM_STARE B ON A.EXAM_ID = B.EXAM_ID AND T.SP < NVL(B.ACQS_TOT_SCR, 0) AND T.EP >= NVL(B.ACQS_TOT_SCR, 0) AND B.DELYN = 'N' AND B.STD_ID IN (SELECT STD_ID FROM TB_LMS_ATNDLC_SBJCT WHERE ATNDLC_STSCD = 'S' AND SBJCT_ID = #{crsCreCd}) WHERE A.EXAM_ID = #{examCd} GROUP BY T.LABEL, T.ODR
ORDER BY T.ODR

/* SQL ID : ExamStareDAO.selectStuExamInfo 설 명 : 시험 정보 및 학생의 시험 응시정보 조회 */ SELECT A.EXAM_ID AS examCd , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = (SELECT AA.USER_ID FROM TB_LMS_ATNDLC_SBJCT AS AA WHERE STD_ID = B.STD_ID)) AS userNm , B.STD_ID AS stdNo , A.EXAM_TTL AS examTitle , A.EXAM_CTS AS examCts , A.TKEXAM_TYCD AS examStareTypeCd , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = A.ORG_ID AND CTGRCD = 'EXAM_STARE_UNI_CD' AND CD = A.TKEXAM_TYCD LIMIT 1) AS examStareTypeNm , DATE_FORMAT(STR_TO_DATE(A.EXAM_SDTTM, '%Y%m%d%H%i%s'), '%Y.%m.%d %H:%i') AS examStartDttm , DATE_FORMAT(STR_TO_DATE(A.EXAM_EDTTM, '%Y%m%d%H%i%s'), '%Y.%m.%d %H:%i') AS examEndDttm , CASE WHEN A.REEXAMYN = 'Y' THEN DATE_FORMAT(STR_TO_DATE(A.RE_EXAM_START_DTTM, '%Y%m%d%H%i%s'), '%Y.%m.%d %H:%i') END AS reExamStartDttm , CASE WHEN A.REEXAMYN = 'Y' THEN DATE_FORMAT(STR_TO_DATE(A.RE_EXAM_END_DTTM, '%Y%m%d%H%i%s'), '%Y.%m.%d %H:%i') END AS reExamEndDttm , A.MRK_OYN AS scoreOpenYn , CASE WHEN A.MRK_OYN = 'Y' THEN DATE_FORMAT(STR_TO_DATE(A.MRK_OPEN_SDTTM, '%Y%m%d%H%i%s'), '%Y.%m.%d %H:%i') END AS scoreOpenDttm , A.TKEXAM_MNTS AS examStareTm , A.MAX_TKEXAM_CNT AS stareLimitCnt , A.EXAMPPR_OYN AS gradeViewYn
, CASE WHEN B.REEXAMYN = 'Y' AND A.RE_EXAM_START_DTTM > FN_DTTM() THEN 'B' WHEN B.REEXAMYN = 'Y' AND FN_DTTM() BETWEEN A.RE_EXAM_START_DTTM AND A.RE_EXAM_END_DTTM THEN 'P' WHEN B.REEXAMYN = 'Y' AND A.RE_EXAM_END_DTTM < FN_DTTM() THEN 'A' WHEN IFNULL(B.REEXAMYN, 'N') = 'N' AND A.EXAM_SDTTM > FN_DTTM() THEN 'B' WHEN IFNULL(B.REEXAMYN, 'N') = 'N' AND FN_DTTM() BETWEEN A.EXAM_SDTTM AND A.EXAM_EDTTM THEN 'P' WHEN IFNULL(B.REEXAMYN, 'N') = 'N' AND A.EXAM_EDTTM < FN_DTTM() THEN 'A' END AS periodTypeCd
, IFNULL(B.ACQS_TOT_SCR,0) AS totGetScore , B.STARE_CNT AS stareCnt , B.STARE_TM AS stareTm , DATE_FORMAT(STR_TO_DATE(B.SDTTM, '%Y%m%d%H%i%s'), '%Y.%m.%d %H:%i:%s') AS stareStartDt , DATE_FORMAT(STR_TO_DATE(B.EDTTM, '%Y%m%d%H%i%s'), '%Y.%m.%d %H:%i:%s') AS stareEndDt , B.EVLYN AS evalYn , DATE_FORMAT(STR_TO_DATE(B.EVL_DTTM, '%Y%m%d%H%i%s'), '%Y.%m.%d %H:%i:%s') AS evalDt , B.REEXAMYN AS reExamYn , ( SELECT SUM(BB.QSTN_SCR) FROM TB_LMS_EXAM_STARE_PAPER AA JOIN TB_LMS_EXAM_QSTN BB ON AA.EXAM_ID = BB.EXAM_ID AND AA.EXAM_QSTN_NO = BB.EXAM_QSTN_NO WHERE AA.EXAM_ID = A.EXAM_ID AND AA.STD_ID = B.STD_ID ) AS fullScore FROM TB_LMS_EXAM_BSC A LEFT JOIN TB_LMS_EXAM_STARE B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' AND B.STD_ID = #{stdNo} WHERE A.EXAM_ID = #{examCd}

/* SQL ID : ExamStareDAO.listExamStareStdCount 설 명 : 시험응시 학습자 수 카운트 */ SELECT COUNT(1) FROM ( WITH STD_T AS ( SELECT #{stdNos} AS STD_ID FROM DUAL ) , COPY_T(N) AS ( SELECT 1 FROM DUAL UNION ALL SELECT N + 1 FROM COPY_T, STD_T
WHERE N <= LENGTH(STD_ID) - LENGTH(REPLACE(STD_ID, ',', ''))
) SELECT A.EXAM_ID , A.ACQS_TOT_SCR , A.ACQS_TOT_SCR AS EVL_SCR , NVL(( SELECT SUM(AA.ACQS_SCR) FROM TB_LMS_EXAM_STARE_PAPER AA WHERE AA.EXAM_ID = A.EXAM_ID AND AA.STD_ID = A.STD_ID ), 0) AS STARE_SCORE , A.EVLYN , A.STD_ID , B.USER_ID , C.USERNM , C.DEPTNM , D.USER_ID , (SELECT CASE WHEN AA.EXAM_CTGRCD = 'EXAM' THEN CASE WHEN A.STARE_CNT > 0 THEN 'C' ELSE 'N' END ELSE CASE WHEN A.SDTTM IS NULL THEN 'N' WHEN A.EDTTM IS NULL THEN 'T' WHEN A.EDTTM IS NOT NULL THEN 'C' END END FROM TB_LMS_EXAM_BSC AA WHERE AA.EXAM_ID = A.EXAM_ID ) AS STARE_STATUS_CD , A.SDTTM , A.EDTTM , A.EVL_DTTM , A.REEXAMYN , A.STARE_CNT , A.STARE_TM , CASE WHEN T.STD_ID IS NOT NULL THEN 'Y' ELSE 'N' END AS CHECK_YN , NVL(B.SCYR, '-') AS SCYR FROM TB_LMS_EXAM_STARE A JOIN TB_LMS_ATNDLC_SBJCT B ON A.STD_ID = B.STD_ID AND B.SBJCT_ID = (SELECT SBJCT_ID FROM TB_LMS_EXAM_CRE_CRS_RLTN WHERE EXAM_ID = #{examCd}) JOIN TB_LMS_USR C ON B.USER_ID = C.USER_ID JOIN TB_LMS_USER_ACNT D ON C.USER_ID = D.USER_ID LEFT JOIN ( SELECT DISTINCT REGEXP_SUBSTR(STD_ID, '[^,]+', 1, N)AS STD_ID FROM COPY_T, STD_T ) T ON A.STD_ID = T.STD_ID WHERE A.EXAM_ID = #{examCd} AND A.DELYN = 'N'
AND (C.USERNM LIKE CONCAT('%', #{searchValue}, '%') COLLATE utf8mb4_general_ci OR C.DEPTNM LIKE CONCAT('%', #{searchValue}, '%') COLLATE utf8mb4_general_ci OR D.USER_ID LIKE CONCAT('%', #{searchValue}, '%') ) COLLATE utf8mb4_general_ci
) T

mapper.update:
	/*
   		SQL ID : ExamStareDAO.updateExamStare
   		설  명 : 시험응시 교수 메모 수정
     */
	UPDATE TB_LMS_EXAM_STARE SET
		  MDFR_ID = #{mdfrId}
		, MOD_DTTM = FN_DTTM()
		, SCR_MEMO = #{profMemo}
	 WHERE STD_ID = #{stdNo}
	   AND EXAM_ID = #{examCd}

	/*
   		SQL ID : ExamStareDAO.updateExamStareExcel
   		설  명 : 시험 엑셀 성적 등록
     */
     UPDATE TB_LMS_EXAM_STARE SET
     	  MDFR_ID = #{mdfrId}
     	, MOD_DTTM = FN_DTTM()
     	, ACQS_TOT_SCR = #{totGetScore}
     	, EVLYN = 'Y'
     	, EVL_DTTM = FN_DTTM()
      WHERE EXAM_ID = #{examCd}
        AND STD_ID IN (
        				SELECT
        					STD_ID
        				  FROM TB_LMS_ATNDLC_SBJCT
        				 WHERE USER_ID = #{userId}
        				   AND SBJCT_ID = (
        				 						SELECT
        				 							SBJCT_ID
        				 						  FROM TB_LMS_EXAM_CRE_CRS_RLTN
        				 						 WHERE EXAM_ID = #{examCd}
        				 					)
        			)

mapper.delete:
	/*
   		SQL ID : ExamStareDAO.deleteAllStare
   		설  명 : 시험 응시 전체 삭제
     */
     DELETE FROM TB_LMS_EXAM_STARE
      WHERE EXAM_ID = #{examCd}

mapper.sql:
WITH CRE_CRS_T AS ( SELECT A.SBJCT_ID , A.SBJCTNM , A.CRS_ID , A.DVCLAS_NO , A.UNIV_CD , (SELECT DEPTNM FROM TB_HOME_USER_DEPT_CD WHERE DEPT_CD = A.DEPT_CD AND ORG_ID = #{orgId}) AS CRS_CRE_DEPT_NM , C.USER_ID AS TCH_NO , (SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = C.USER_ID) AS TCH_NM FROM TB_LMS_SBJCT A JOIN TB_LMS_TERM_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID AND B.CRS_SMSTR_ID = #{termCd} LEFT JOIN SBJCT_PROF C ON A.SBJCT_ID = C.SBJCT_ID AND C.RPRSYN = 'Y' WHERE A.DELYN = 'N' AND A.USEYN = 'Y'
AND A.SBJCT_ID = #{crsCreCd}
AND A.DEPT_CD = #{deptCd}
AND A.UNIV_CD = #{uniCd}
AND C.USER_ID = #{tchNo}
AND LOWER((SELECT USERNM FROM TB_LMS_USR WHERE USER_ID = C.USER_ID)) LIKE LOWER(CONCAT('%', #{tchNm}, '%'))
ORDER BY A.UNIV_CD, A.SBJCTNM, A.DVCLAS_NO ) SELECT A.* FROM ( SELECT A.SBJCT_ID , A.SBJCTNM , A.CRS_ID , A.DVCLAS_NO , A.UNIV_CD , A.CRS_CRE_DEPT_NM , A.TCH_NO , A.TCH_NM , A.EXAM_ID , A.EXAM_TTL , A.EXAM_SDTTM , A.TKEXAM_MNTS , A.TKEXAM_TYCD , (SELECT CDNM FROM TB_ORG_CODE WHERE ORG_ID = #{orgId} AND CTGRCD = 'EXAM_STARE_UNI_CD' AND CD = A.TKEXAM_TYCD LIMIT 1) AS EXAM_STARE_TYPE_NM , B.USER_ID , B.USERNM , B.DEPTNM , B.STD_ID , B.EMAIL , B.MOBILE_NO , (SELECT APRV_STSCD FROM TB_LMS_EXAM_ABSNCE WHERE SBJCT_ID = A.SBJCT_ID AND EXAM_ID = A.EXAM_ID AND STD_ID = B.STD_ID ORDER BY FRST_INQ_DTTM DESC LIMIT 1) AS APRV_STSCD , C.REEXAMYN FROM ( -- 강의실별 실시간 시험 SELECT A.SBJCT_ID , A.SBJCTNM , A.CRS_ID , A.DVCLAS_NO , A.UNIV_CD , A.CRS_CRE_DEPT_NM , A.TCH_NO , A.TCH_NM , C.EXAM_ID , C.EXAM_TTL , C.EXAM_SDTTM , C.TKEXAM_MNTS , C.TKEXAM_TYCD , C.REEXAMYN FROM CRE_CRS_T A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.SBJCT_ID = B.SBJCT_ID AND B.DELYN = 'N' JOIN TB_LMS_EXAM_BSC C ON B.EXAM_ID = C.EXAM_ID AND C.DELYN = 'N' AND C.USEYN = 'Y' AND C.EXAM_CTGRCD = 'EXAM' AND C.EXAM_TYCD = 'EXAM' AND C.TKEXAM_TYCD = #{examStareTypeCd} ) A JOIN ( -- 강의실별 수강생 SELECT A.SBJCT_ID , A.STD_ID , C.USER_ID , C.USERNM , C.DEPTNM , C.EMAIL , C.MOBILE_NO FROM TB_LMS_ATNDLC_SBJCT A JOIN TB_LMS_USER_ACNT B ON A.USER_ID = B.USER_ID AND B.ACNT_STSCD = 'U' JOIN TB_LMS_USR C ON A.USER_ID = C.USER_ID WHERE A.ATNDLC_STSCD = 'S' AND A.SBJCT_ID IN ( SELECT SBJCT_ID FROM CRE_CRS_T )
AND A.USER_ID = #{userId}
AND LOWER(C.USERNM) LIKE LOWER(CONCAT('%', #{userNm}, '%'))
) B ON A.SBJCT_ID = B.SBJCT_ID LEFT JOIN TB_LMS_EXAM_STARE C ON A.EXAM_ID = C.EXAM_ID AND B.STD_ID = C.STD_ID AND C.DELYN = 'N' WHERE C.SDTTM IS NULL
AND C.REEXAMYN = #{reExamYn}
) A WHERE 1=1
AND IF(A.APRV_STSCD = 'RAPPLICATE', 'APPLICATE', IFNULL(A.APRV_STSCD, 'NOAPPLICATE')) = #{apprStat}

