mapper.select:
/* SQL ID : ExamStareDAO.selectCreCrsNm 설 명 : 진행중인 과목명 조회 */ SELECT SBJCT_ID , SBJCTNM FROM TB_LMS_SBJCT TLCC WHERE USEYN = 'Y' AND DELYN = 'N'
AND SBJCT_ID = #{haksaYear}
AND CRS_ID = #{haksaTerm}

/* SQL ID : ExamStareDAO.selectIndustryConLearningList 설 명 : 산업체위탁생학습진행현황 조회 */ WITH CRS_STD_INFO AS ( SELECT TLCC.SBJCT_ID , TLS.USER_ID -- 학번 또는 사번 , (SELECT USERNM FROM TB_LMS_USR THUI WHERE TLS.USER_ID = THUI.USER_ID) AS USERNM -- 성명 , TLCC.CRS_ID -- 학수번호 , TLCC.SBJCTNM -- 교과목명 , THUL.LOGIN_CNT -- 로그인횟수 , TLCC.CRDTS -- 학점 , TLS.STD_ID , THUL.USER_ID FROM TB_LMS_SBJCT TLCC INNER JOIN TB_LMS_ATNDLC_SBJCT TLS ON TLCC.SBJCT_ID = TLS.SBJCT_ID INNER JOIN TB_LMS_USER_ACNT THUL ON TLS.USER_ID = THUL.USER_ID AND THUL.ACNT_STSCD = 'U' AND TLS.ATNDLC_STSCD = 'S' WHERE 1 = 1
AND TLCC.SBJCT_ID = #{haksaYear}
AND TLCC.CRS_ID = #{haksaTerm}
AND TLCC.SBJCT_ID = #{crsCreCd}
), LESSON_SCHEDULE_INFO AS ( SELECT SBJCT_ID , USER_ID , STD_ID , CASE WHEN ONE_WEEK = 1 THEN 'O' WHEN ONE_WEEK = 2 THEN '지각' WHEN ONE_WEEK = 3 THEN '결석' WHEN ONE_WEEK = 4 THEN '학습중' END AS ONE_WEEK_RESULT , CASE WHEN TWO_WEEK = 1 THEN 'O' WHEN TWO_WEEK = 2 THEN '지각' WHEN TWO_WEEK = 3 THEN '결석' WHEN TWO_WEEK = 4 THEN '학습중' END AS TWO_WEEK_RESULT , CASE WHEN THREE_WEEK = 1 THEN 'O' WHEN THREE_WEEK = 2 THEN '지각' WHEN THREE_WEEK = 3 THEN '결석' WHEN THREE_WEEK = 4 THEN '학습중' END AS THREE_WEEK_RESULT , CASE WHEN FOUR_WEEK = 1 THEN 'O' WHEN FOUR_WEEK = 2 THEN '지각' WHEN FOUR_WEEK = 3 THEN '결석' WHEN FOUR_WEEK = 4 THEN '학습중' END AS FOUR_WEEK_RESULT , CASE WHEN FIVE_WEEK = 1 THEN 'O' WHEN FIVE_WEEK = 2 THEN '지각' WHEN FIVE_WEEK = 3 THEN '결석' WHEN FIVE_WEEK = 4 THEN '학습중' END AS FIVE_WEEK_RESULT , CASE WHEN SIX_WEEK = 1 THEN 'O' WHEN SIX_WEEK = 2 THEN '지각' WHEN SIX_WEEK = 3 THEN '결석' WHEN SIX_WEEK = 4 THEN '학습중' END AS SIX_WEEK_RESULT , CASE WHEN SEVEN_WEEK = 1 THEN 'O' WHEN SEVEN_WEEK = 2 THEN '지각' WHEN SEVEN_WEEK = 3 THEN '결석' WHEN SEVEN_WEEK = 4 THEN '학습중' END AS SEVEN_WEEK_RESULT , CASE WHEN NINE_WEEK = 1 THEN 'O' WHEN NINE_WEEK = 2 THEN '지각' WHEN NINE_WEEK = 3 THEN '결석' WHEN NINE_WEEK = 4 THEN '학습중' END AS NINE_WEEK_RESULT , CASE WHEN TEN_WEEK = 1 THEN 'O' WHEN TEN_WEEK = 2 THEN '지각' WHEN TEN_WEEK = 3 THEN '결석' WHEN TEN_WEEK = 4 THEN '학습중' END AS TEN_WEEK_RESULT , CASE WHEN ELEVEN_WEEK = 1 THEN 'O' WHEN ELEVEN_WEEK = 2 THEN '지각' WHEN ELEVEN_WEEK = 3 THEN '결석' WHEN ELEVEN_WEEK = 4 THEN '학습중' END AS ELEVEN_WEEK_RESULT , CASE WHEN TWELVE_WEEK = 1 THEN 'O' WHEN TWELVE_WEEK = 2 THEN '지각' WHEN TWELVE_WEEK = 3 THEN '결석' WHEN TWELVE_WEEK = 4 THEN '학습중' END AS TWELVE_WEEK_RESULT , CASE WHEN THIRTEEN_WEEK = 1 THEN 'O' WHEN THIRTEEN_WEEK = 2 THEN '지각' WHEN THIRTEEN_WEEK = 3 THEN '결석' WHEN THIRTEEN_WEEK = 4 THEN '학습중' END AS THIRTEEN_WEEK_RESULT , CASE WHEN FOURTEEN_WEEK = 1 THEN 'O' WHEN FOURTEEN_WEEK = 2 THEN '지각' WHEN FOURTEEN_WEEK = 3 THEN '결석' WHEN FOURTEEN_WEEK = 4 THEN '학습중' END AS FOURTEEN_WEEK_RESULT , CASE WHEN SIXTEEN_WEEK = 1 THEN 'O' WHEN SIXTEEN_WEEK = 2 THEN '지각' WHEN SIXTEEN_WEEK = 3 THEN '결석' WHEN SIXTEEN_WEEK = 4 THEN '학습중' END AS SIXTEEN_WEEK_RESULT FROM (SELECT SBJCT_ID , USER_ID , STD_ID , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 1 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS ONE_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 2 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS TWO_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 3 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS THREE_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 4 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS FOUR_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 5 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS FIVE_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 6 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS SIX_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 7 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS SEVEN_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 9 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS NINE_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 10 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS TEN_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 11 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS ELEVEN_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 12 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS TWELVE_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 13 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS THIRTEEN_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 14 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS FOURTEEN_WEEK , SUM(IFNULL(CASE WHEN LCTR_SCHDL_SEQ = 16 THEN IF(ATNDLC_STSCD = 'COMPLETE', 1, IF(ATNDLC_STSCD = 'LATE', 2, IF(ATNDLC_STSCD = 'NOSTUDY', 3, IF(ATNDLC_STSCD = 'STUDY', 4, 0)))) END, 0)) AS SIXTEEN_WEEK FROM (SELECT TLLS.SBJCT_ID , LCTR_SCHDL_SEQ , USER_ID , STD_ID , ATNDLC_STSCD FROM TB_LMS_SBJCT_LCTR_SCHDL TLLS INNER JOIN TB_LMS_SBJCT TLCC ON TLLS.SBJCT_ID = tlcc.SBJCT_ID LEFT JOIN TB_LMS_LESSON_STUDY_STATE TLLSS ON TLLSS .LCTR_SCHDL_ID = TLLS .LCTR_SCHDL_ID WHERE USER_ID IS NOT NULL
AND TLCC.SBJCT_ID = #{haksaYear}
AND TLCC.CRS_ID = #{haksaTerm}
AND TLCC.SBJCT_ID = #{crsCreCd}
) A GROUP BY SBJCT_ID, USER_ID, STD_ID) AA ), MIDDLE_EXAM_INFO as ( SELECT SBJCT_ID , STD_ID , TKEXAM_TYCD , CASE WHEN IFNULL(EIGHT_WEEK_RESULT, '-') = '0' THEN '미제출' WHEN IFNULL(EIGHT_WEEK_RESULT, '-') = '1' THEN '제출' ELSE IFNULL(EIGHT_WEEK_RESULT, '-') END EIGHT_WEEK_RESULT FROM (SELECT SBJCT_ID , TLECCR.EXAM_ID , STD_ID , TLE.EXAM_SBST_REF_ID , TKEXAM_TYCD , STARE_CNT , CASE WHEN TLE.EXAM_SBST_REF_ID IS NULL AND TKEXAM_TYCD = 'M' THEN CASE WHEN IFNULL(STARE_CNT, 0) > 0 THEN CONCAT('중간고사 ', DATE_FORMAT(SDTTM, '%m.%d %h:%m')) -- 시험을 응시 ELSE '-' -- 시험을 미응시 END WHEN TLE.EXAM_SBST_REF_ID IS NOT NULL AND TKEXAM_TYCD = 'M' THEN -- 실시간 시험이면서 과제,토론,퀴즈로 대체 할 수 있다. CASE WHEN IFNULL(STARE_CNT, 0) > 0 THEN CONCAT('중간고사 ', DATE_FORMAT(SDTTM, '%m.%d %h:%m')) WHEN IFNULL(STARE_CNT, 0) = 0 THEN CASE WHEN SUBSTR(TLE.EXAM_SBST_REF_ID, 1, 4) = 'EXAM' THEN (SELECT IFNULL(STARE_CNT, '0') FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = TLES.EXAM_ID AND STD_ID = TLES.STD_ID) WHEN SUBSTR(TLE.EXAM_SBST_REF_ID, 1, 5) = 'ASMNT' THEN (SELECT CASE WHEN SBMSN_STSCD IN ('SUMBIT', 'LATE', 'RE') THEN '1' ELSE '0' END FROM TB_LMS_ASMT_SBMSN WHERE ASMT_SBMSN_ID = TLES.EXAM_ID AND STD_ID = TLES.STD_ID) WHEN SUBSTR(TLE.EXAM_SBST_REF_ID, 1, 5) = 'FORUM' THEN (SELECT COUNT(1) FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = TLES.EXAM_ID AND STD_ID = TLES.STD_ID) END END END EIGHT_WEEK_RESULT FROM TB_LMS_EXAM_CRE_CRS_RLTN TLECCR INNER JOIN TB_LMS_EXAM_BSC TLE ON TLECCR.EXAM_ID = TLE.EXAM_ID AND TLE.EXAM_CTGRCD = 'EXAM' AND TLECCR.DELYN = 'N' AND TLE.TKEXAM_TYCD = 'M' LEFT JOIN TB_LMS_EXAM_STARE TLES ON TLECCR.EXAM_ID = TLES.EXAM_ID WHERE 1 = 1
AND TLECCR.SBJCT_ID = #{crsCreCd}
AND TLECCR.SBJCT_ID IN ( SELECT SBJCT_ID FROM TB_LMS_SBJCT TLCC WHERE 1 = 1
AND TLCC.SBJCT_ID = #{haksaYear}
AND TLCC.CRS_ID = #{haksaTerm}
)
) A ), LAST_EXAM_INFO as ( SELECT SBJCT_ID , STD_ID , TKEXAM_TYCD , CASE WHEN IFNULL(FIFTEEN_WEEK_RESULT, '-') = '0' THEN '미제출' WHEN IFNULL(FIFTEEN_WEEK_RESULT, '-') = '1' THEN '제출' ELSE IFNULL(FIFTEEN_WEEK_RESULT, '-') END FIFTEEN_WEEK_RESULT FROM (SELECT SBJCT_ID , TLECCR.EXAM_ID , STD_ID , TLE.EXAM_SBST_REF_ID , TKEXAM_TYCD , STARE_CNT , CASE WHEN TLE.EXAM_SBST_REF_ID IS NULL AND TKEXAM_TYCD = 'L' THEN CASE WHEN IFNULL(STARE_CNT, 0) > 0 THEN CONCAT('기말고사 ', DATE_FORMAT(SDTTM, '%m.%d %h:%m')) -- 시험을 응시 ELSE '-' -- 시험을 미응시 END WHEN TLE.EXAM_SBST_REF_ID IS NOT NULL AND TKEXAM_TYCD = 'L' THEN -- 실시간 시험이면서 과제,토론,퀴즈로 대체 할 수 있다. CASE WHEN IFNULL(STARE_CNT, 0) > 0 THEN CONCAT('기말고사 ', DATE_FORMAT(SDTTM, '%m.%d %h:%m')) WHEN IFNULL(STARE_CNT, 0) = 0 THEN CASE WHEN SUBSTR(TLE.EXAM_SBST_REF_ID, 1, 4) = 'EXAM' THEN (SELECT IFNULL(STARE_CNT, '0') FROM TB_LMS_EXAM_STARE WHERE EXAM_ID = TLES.EXAM_ID AND STD_ID = TLES.STD_ID) WHEN SUBSTR(TLE.EXAM_SBST_REF_ID, 1, 5) = 'ASMNT' THEN (SELECT CASE WHEN SBMSN_STSCD IN ('SUMBIT', 'LATE', 'RE') THEN '1' ELSE '0' END FROM TB_LMS_ASMT_SBMSN WHERE ASMT_SBMSN_ID = TLES.EXAM_ID AND STD_ID = TLES.STD_ID) WHEN SUBSTR(TLE.EXAM_SBST_REF_ID, 1, 5) = 'FORUM' THEN (SELECT COUNT(1) FROM TB_LMS_DSCS_ATCL WHERE DSCS_ID = TLES.EXAM_ID AND STD_ID = TLES.STD_ID) END END END FIFTEEN_WEEK_RESULT FROM TB_LMS_EXAM_CRE_CRS_RLTN TLECCR INNER JOIN TB_LMS_EXAM_BSC TLE ON TLECCR.EXAM_ID = TLE.EXAM_ID AND TLE.EXAM_CTGRCD = 'EXAM' AND TLECCR.DELYN = 'N' AND TLE.TKEXAM_TYCD = 'L' LEFT JOIN TB_LMS_EXAM_STARE TLES ON TLECCR.EXAM_ID = TLES.EXAM_ID WHERE 1 = 1
AND TLECCR.SBJCT_ID = #{crsCreCd}
AND TLECCR.SBJCT_ID IN ( SELECT SBJCT_ID FROM TB_LMS_SBJCT TLCC WHERE 1 = 1
AND TLCC.SBJCT_ID = #{haksaYear}
AND TLCC.CRS_ID = #{haksaTerm}
)
) A ) SELECT ROW_NUMBER() OVER(ORDER BY CSI.USERNM) AS LINE_NO -- No , CSI.USER_ID -- 학번 또는 사번 , CSI.USERNM -- 성명 , CSI.CRS_ID -- 학수번호 , CSI.SBJCTNM -- 교과목명 , IFNULL(LSI.ONE_WEEK_RESULT, '-') AS ONE_WEEK_RESULT -- 1차시 , IFNULL(LSI.TWO_WEEK_RESULT, '-') AS TWO_WEEK_RESULT -- 2차시 , IFNULL(LSI.THREE_WEEK_RESULT, '-') AS THREE_WEEK_RESULT -- 3차시 , IFNULL(LSI.FOUR_WEEK_RESULT, '-') AS FOUR_WEEK_RESULT -- 4차시 , IFNULL(LSI.FIVE_WEEK_RESULT, '-') AS FIVE_WEEK_RESULT -- 5차시 , IFNULL(LSI.SIX_WEEK_RESULT, '-') AS SIX_WEEK_RESULT -- 6차시 , IFNULL(LSI.SEVEN_WEEK_RESULT, '-') AS SEVEN_WEEK_RESULT -- 7차시 , IFNULL(MEI.EIGHT_WEEK_RESULT, '-') AS EIGHT_WEEK_RESULT -- 8차시 , IFNULL(LSI.NINE_WEEK_RESULT, '-') AS NINE_WEEK_RESULT -- 9차시 , IFNULL(LSI.TEN_WEEK_RESULT, '-') AS TEN_WEEK_RESULT -- 10차시 , IFNULL(LSI.ELEVEN_WEEK_RESULT, '-') AS ELEVEN_WEEK_RESULT -- 11차시 , IFNULL(LSI.TWELVE_WEEK_RESULT, '-') AS TWELVE_WEEK_RESULT -- 12차시 , IFNULL(LSI.THIRTEEN_WEEK_RESULT, '-') AS THIRTEEN_WEEK_RESULT -- 13차시 , IFNULL(LSI.FOURTEEN_WEEK_RESULT, '-') AS FOURTEEN_WEEK_RESULT -- 14차시 , IFNULL(LEI.FIFTEEN_WEEK_RESULT, '-') AS FIFTEEN_WEEK_RESULT -- 15차시 , IFNULL(LSI.SIXTEEN_WEEK_RESULT, '-') AS SIXTEEN_WEEK_RESULT -- 16차시 , IFNULL(CSI.LOGIN_CNT, '0') AS LOGIN_CNT -- 로그인횟수 , CSI.CRDTS -- 학점 , 0.0 AS MEAN_RATING -- 평균평점 , IFNULL(TOT_SCR, '0.0') AS TOT_SCR -- 백분율점수 , IFNULL(SCR_GRDCD, '') AS SCR_GRDCD -- 등급 FROM CRS_STD_INFO CSI LEFT JOIN LESSON_SCHEDULE_INFO LSI ON CSI.SBJCT_ID = LSI.SBJCT_ID AND CSI.USER_ID = LSI.USER_ID AND CSI.STD_ID = LSI.STD_ID LEFT JOIN MIDDLE_EXAM_INFO MEI ON CSI.SBJCT_ID = MEI.SBJCT_ID AND CSI.STD_ID = MEI.STD_ID LEFT JOIN LAST_EXAM_INFO LEI ON CSI.SBJCT_ID = LEI.SBJCT_ID AND CSI.STD_ID = LEI.STD_ID LEFT JOIN TB_LMS_MRK_SBJCT TLSS ON CSI.STD_ID = TLSS.STD_ID

/* SQL ID : ExamStareDAO.listExamNoStare 설 명 : 대체평가 대상자 목록 */ SELECT ROW_NUMBER() OVER(ORDER BY D.USERNM) AS LINE_NO , D.DEPTNM , D.USER_ID , D.USERNM , D.EMAIL , D.MOBILE_NO , C.STD_ID , CASE WHEN NVL(E.STARE_CNT, 0) = 0 THEN 'N' ELSE 'Y' END AS STARE_YN , CASE WHEN (SELECT COUNT(EXAM_ABSNCE_ID) FROM TB_LMS_EXAM_ABSNCE WHERE EXAM_ID = A.EXAM_ID AND STD_ID = C.STD_ID) > 0 THEN 'Y' ELSE 'N' END AS ABSENT_YN , NVL(( SELECT APRV_STSCD FROM TB_LMS_EXAM_ABSNCE WHERE FRST_INQ_DTTM = ( SELECT MAX(FRST_INQ_DTTM) FROM TB_LMS_EXAM_ABSNCE WHERE EXAM_ID = A.EXAM_ID AND STD_ID = C.STD_ID )), '-') AS ABSENT_NM FROM TB_LMS_EXAM_BSC A JOIN TB_LMS_EXAM_CRE_CRS_RLTN B ON A.EXAM_ID = B.EXAM_ID AND B.DELYN = 'N' JOIN TB_LMS_ATNDLC_SBJCT C ON B.SBJCT_ID = C.SBJCT_ID AND C.ATNDLC_STSCD = 'S' AND C.AUDITYN = 'N' JOIN TB_LMS_USR D ON C.USER_ID = D.USER_ID LEFT JOIN TB_LMS_EXAM_STARE E ON A.EXAM_ID = E.EXAM_ID AND C.STD_ID = E.STD_ID WHERE A.EXAM_ID = #{examCd} AND A.DELYN = 'N' AND C.SBJCT_ID = #{crsCreCd}
AND E.REEXAMYN = 'Y'
AND ( E.REEXAMYN = 'N' OR E.REEXAMYN IS NULL ) AND ( E.STARE_CNT = 0 OR E.STARE_CNT IS NULL )
